// Normalize incoming client data
const body = $input.all()[0].json.body || $input.all()[0].json;
return [{ json: { ...body, received_at: new Date().toISOString() } }];

// Wait for all parallel tasks and prepare roster entry
const input = $('Normalize Input').first().json;
const clickupSpace = $('Create ClickUp Space').first().json;
const onedrive = $('Create OneDrive Folder').first().json;
const forecastSheet = $('Create Forecast Sheet').first().json;

return [{
  json: {
    'Client Name': input.company_name,
    'Status': 'Active',
    'ClickUp Space ID': clickupSpace.id || 'CONFIGURE',
    'Google Drive Folder ID': 'CONFIGURE',
    'OneDrive Folder Path': `/Clients/${input.company_name}`,
    'Primary Contact Email': input.contact_email,
    'Primary Contact Name': input.primary_contact,
    'CC Emails': '',
    'Forecast Sheet ID': forecastSheet.spreadsheetId || 'CONFIGURE',
    'Meeting Day': 'CONFIGURE',
    'Meeting Time': 'CONFIGURE',
    'Update Preference': 'detailed',
    'Retainer Hours/Month': '',
    'Hourly Rate': '',
    'Toggl Project ID': '',
    'HubSpot Deal ID': '',
    'LinkedIn Company URL': '',
    'Slack Channel': '',
    'Notes': `${input.scope_tier} engagement, ${input.duration}. ARR: $${input.arr}`,
    original_input: input
  }
}];

